import React from 'react'
import { Smart } from "../components/data/Smart";
import { Nout } from '../components/data/Nout';
import { Link } from 'react-router-dom'



function First() {
    return (
        <div className="First">
            <ul class="lightrope">
                <li></li><li></li><li></li><li></li><li></li><li></li>
            </ul>
            <div className="First-name">

                <h1>Смартфоны и ноутбуки в Уральске</h1>
            </div>
            {
                Smart.map(element => (
                    <Link to={"p/" + element.id} className="First__card">

                        <div key={element.id} >
                            <div className="sskid">{element.skid}</div>
                            <img src={element.img} alt={element.title} />
                            <h1>{element.title}</h1>
                            <p><div className="cost"> Цена:</div> {element.cost}</p>
                        </div>
                    </Link>
                ))
            }

            {
                Nout.map(element => (
                    <Link to={"p/" + element.id} className="First__card">
                        <div key={element.id} >
                            <div className="sskid">{element.skid}</div>
                            <img src={element.img} alt={element.title} />
                            <h1>{element.title}</h1>
                            <p><div className="cost"> Цена:</div> {element.cost}</p>
                        </div>
                    </Link>
                ))
            }
        </div >
    );
}

export default First;
